class Customer:
    bookings = []

    def __init__(self, name, address, contact):
        self.name = name
        self.address = address
        self.contact = contact

class FrequentFlyer(Customer):
    def __init__(self, name, address, contact):
        super().__init__(name, address, contact)
        self.frequent_flyer_points = 0

    def add_points(self, points):
        self.frequent_flyer_points += points

    def redeem_points(self, points):
        if points <= self.frequent_flyer_points:
            self.frequent_flyer_points -= points
        else:
            print("Insufficient points")

# Do not modify the code below. This function will be called during testing.
def default_test():
    frequent_flyer = FrequentFlyer(name="Jane Doe", address="123 Main St", contact="9876543210")
    print(frequent_flyer.name)
    print(frequent_flyer.address)
    print(frequent_flyer.contact)
    frequent_flyer.add_points(1000)
    frequent_flyer.redeem_points(500)
    print(frequent_flyer.frequent_flyer_points)
